// 2.8.3 | 2023-05-26 | raj | DFCT0011460 - The "Original Suspense Date" is updated to the current suspense date after changing the suspense date on the Task form. Changing the suspense date a second time
// 2.7.3 | 2022-05-12 | raj | STRY0014827 - Due Date (Suspense date) Change – Email Notification
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// DFCT0011460 - also changed this businesss rule to onInsert and onUpdate
	if(current.original_suspense_date == '' && current.suspense_date != ""){
		current.setValue("original_suspense_date", current.getValue("suspense_date"));
		current.work_notes = "The Original Suspense Date is: " + current.original_suspense_date;
	}
	// this logic was only in the update, so added newRecord check so nothing in the standard logic should change
	if(!current.extension_requested && !current.isNewRecord()){
		// STRY0017099 KB 2019-05-08 Update Activity Log (who, Previous Suspense Date, New Suspense Date)
		current.work_notes = "Suspense date updated by " + gs.getUserDisplayName() + "\n Previous: " + previous.suspense_date + "\n New: " + current.suspense_date;	

		// STRY0014827
		// by sending this only when the extension request is false we can make sure we don't send it when previous was true as that 
		// would happen when the request is cleared by the user and a differnet notificaiton is sent.
		// Also make sure the state is not waiting and state is not draft
		if(!(!current.extension_requested && previous.extension_requested) && 
			(!current.suspense_date.nil() && current.suspense_date != '') &&
			(current.state != -3 && current.state != -6)){
			gs.eventQueue('x_153465_discovert.Tasker_Suspense_Date_', current);
		}	
	}



})(current, previous);
